+import { describe, it, expect, beforeEach } from 'vitest';
+import {
+  EmailAdapter,
+  InMemoryTransport,
+} from '../../src/adapters/email.adapter.js';
+import type {
+  EmailTransport,
+  RenderedEmail,
+} from '../../src/adapters/email.adapter.js';
+import type { NotificationPayload } from '../../src/models/notification.js';
+
+function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
+  return {
+    id: 'notif-0001',
+    type: 'order-confirmation',
+    channel: 'email',
+    recipient: 'alice@example.com',
+    subject: 'Order Confirmation: order-1',
+    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
+    priority: 'normal',
+    metadata: {},
+    createdAt: new Date(),
+    ...overrides,
+  };
+}
+
+describe('EmailAdapter', () => {
+  let adapter: EmailAdapter;
+  let transport: InMemoryTransport;
+
+  beforeEach(() => {
+    transport = new InMemoryTransport();
+    adapter = new EmailAdapter(
+      { fromAddress: 'noreply@taskflow.io', fromName: 'TaskFlow Pro' },
+      transport,
+    );
+  });
+
+  describe('channel', () => {
+    it('should report channel as email', () => {
+      expect(adapter.channel).toBe('email');
+    });
+  });
+
+  describe('isAvailable', () => {
+    it('should return true when transport is connected', async () => {
+      expect(await adapter.isAvailable()).toBe(true);
+    });
+
+    it('should return false when transport throws', async () => {
+      const failTransport: EmailTransport = {
+        send: async () => ({ success: true }),
+        isConnected: async () => { throw new Error('connection lost'); },
+      };
+      const failAdapter = new EmailAdapter(
+        { fromAddress: 'a@b.com', fromName: 'Test' },
+        failTransport,
+      );
+      expect(await failAdapter.isAvailable()).toBe(false);
+    });
+  });
+
+  describe('send', () => {
+    it('should send successfully and track the payload', async () => {
+      const payload = makePayload();
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(true);
+      expect(result.notificationId).toBe('notif-0001');
+      expect(result.channel).toBe('email');
+      expect(result.deliveredAt).toBeInstanceOf(Date);
+
+      expect(adapter.getSentEmails()).toHaveLength(1);
+      expect(adapter.getSentEmails()[0]?.id).toBe('notif-0001');
+    });
+
+    it('should construct a proper rendered email sent to transport', async () => {
+      const payload = makePayload();
+      await adapter.send(payload);
+
+      const sent = transport.getSentEmails();
+      expect(sent).toHaveLength(1);
+      expect(sent[0]?.from).toBe('TaskFlow Pro <noreply@taskflow.io>');
+      expect(sent[0]?.to).toBe('alice@example.com');
+      expect(sent[0]?.subject).toBe('Order Confirmation: order-1');
+      expect(sent[0]?.html).toContain('Order Confirmation');
+      expect(sent[0]?.text).toContain('Widget x2');
+    });
+
+    it('should return failure when transport fails', async () => {
+      const failTransport: EmailTransport = {
+        send: async () => ({ success: false, error: 'SMTP timeout' }),
+        isConnected: async () => true,
+      };
+      const failAdapter = new EmailAdapter(
+        { fromAddress: 'a@b.com', fromName: 'Test', maxRetries: 0 },
+        failTransport,
+      );
+
+      const result = await failAdapter.send(makePayload());
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('SMTP timeout');
+    });
+
+    it('should return failure when recipient is empty', async () => {
+      const payload = makePayload({ recipient: '  ' });
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Recipient is empty');
+    });
+
+    it('should still deliver when recipient has no @ sign', async () => {
+      const payload = makePayload({ recipient: 'user-123' });
+      const result = await adapter.send(payload);
+
+      // Delivers as-is (the service is responsible for providing correct email)
+      expect(result.success).toBe(true);
+      const sent = transport.getSentEmails();
+      expect(sent[0]?.to).toBe('user-123');
+    });
+  });
+
+  describe('retry logic', () => {
+    it('should retry on failure up to maxRetries', async () => {
+      let attempts = 0;
+      const flakyTransport: EmailTransport = {
+        send: async () => {
+          attempts++;
+          if (attempts < 3) {
+            return { success: false, error: 'transient' };
+          }
+          return { success: true };
+        },
+        isConnected: async () => true,
+      };
+
+      const retryAdapter = new EmailAdapter(
+        { fromAddress: 'a@b.com', fromName: 'Test', maxRetries: 2 },
+        flakyTransport,
+      );
+
+      const result = await retryAdapter.send(makePayload());
+      expect(result.success).toBe(true);
+      expect(attempts).toBe(3); // 1 initial + 2 retries
+    });
+
+    it('should give up after maxRetries exhausted', async () => {
+      const failTransport: EmailTransport = {
+        send: async () => ({ success: false, error: 'always fails' }),
+        isConnected: async () => true,
+      };
+
+      const retryAdapter = new EmailAdapter(
+        { fromAddress: 'a@b.com', fromName: 'Test', maxRetries: 1 },
+        failTransport,
+      );
+
+      const result = await retryAdapter.send(makePayload());
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('always fails');
+    });
+  });
+
+  describe('template rendering', () => {
+    it('should render order-confirmation template', () => {
+      const payload = makePayload({ type: 'order-confirmation' });
+      const rendered = adapter.renderTemplate(payload);
+
+      expect(rendered.html).toContain('Order Confirmation');
+      expect(rendered.html).toContain('Widget x2');
+      expect(rendered.text).toContain('Order Confirmation');
+      expect(rendered.text).toContain('TaskFlow Pro');
+    });
+
+    it('should render order-status-update template', () => {
+      const payload = makePayload({
+        type: 'order-status-update',
+        body: 'Status changed from pending to confirmed.',
+      });
+      const rendered = adapter.renderTemplate(payload);
+
+      expect(rendered.html).toContain('Order Status Update');
+      expect(rendered.html).toContain('pending to confirmed');
+      expect(rendered.text).toContain('pending to confirmed');
+    });
+
+    it('should render user-welcome template', () => {
+      const payload = makePayload({
+        type: 'user-welcome',
+        subject: 'Welcome to TaskFlow Pro, Alice!',
+        body: 'Your account has been created.',
+      });
+      const rendered = adapter.renderTemplate(payload);
+
+      expect(rendered.html).toContain('Welcome to TaskFlow Pro, Alice!');
+      expect(rendered.html).toContain('Get started');
+      expect(rendered.text).toContain('Get started');
+    });
+
+    it('should render user-updated template', () => {
+      const payload = makePayload({
+        type: 'user-updated',
+        body: 'Your profile was updated.',
+      });
+      const rendered = adapter.renderTemplate(payload);
+
+      expect(rendered.html).toContain('Account Updated');
+      expect(rendered.text).toContain('Your profile was updated.');
+    });
+
+    it('should render system-alert template with alert styling', () => {
+      const payload = makePayload({
+        type: 'system-alert',
+        subject: 'High CPU Usage',
+        body: 'Server load exceeded threshold.',
+      });
+      const rendered = adapter.renderTemplate(payload);
+
+      expect(rendered.html).toContain('System Alert');
+      expect(rendered.html).toContain('#e53e3e');
+      expect(rendered.text).toContain('[ALERT]');
+    });
+
+    it('should escape HTML in body content', () => {
+      const payload = makePayload({
+        body: '<script>alert("xss")</script>',
+      });
+      const rendered = adapter.renderTemplate(payload);
+
+      expect(rendered.html).not.toContain('<script>');
+      expect(rendered.html).toContain('&lt;script&gt;');
+    });
+  });
+
+  describe('getSentEmails / clearSentEmails', () => {
+    it('should return a copy of sent emails', async () => {
+      await adapter.send(makePayload());
+      const sent = adapter.getSentEmails();
+      sent.pop(); // mutate the copy
+      expect(adapter.getSentEmails()).toHaveLength(1);
+    });
+
+    it('should clear sent emails', async () => {
+      await adapter.send(makePayload());
+      adapter.clearSentEmails();
+      expect(adapter.getSentEmails()).toHaveLength(0);
+    });
+  });
+
+  describe('InMemoryTransport', () => {
+    it('should store and return sent emails', async () => {
+      const email: RenderedEmail = {
+        from: 'a@b.com',
+        to: 'c@d.com',
+        subject: 'Test',
+        html: '<p>Hi</p>',
+        text: 'Hi',
+      };
+
+      const result = await transport.send(email);
+      expect(result.success).toBe(true);
+      expect(transport.getSentEmails()).toHaveLength(1);
+      expect(transport.getSentEmails()[0]?.to).toBe('c@d.com');
+    });
+
+    it('should clear stored emails', async () => {
+      await transport.send({
+        from: 'a@b.com', to: 'c@d.com', subject: 'X', html: '', text: '',
+      });
+      transport.clearSentEmails();
+      expect(transport.getSentEmails()).toHaveLength(0);
